import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalCase() {
        // apple=3, banana=2, cherry=1 => top-2: [apple, banana]
        String[] words = {"apple","banana","apple","cherry","banana","apple"};
        assertEquals(List.of("apple","banana"), new Solution().topKFrequentWords(words, 2));
    }

    @Test
    void tiebreakByLexAscending() {
        // a=2, b=2, c=2; tiebreak lex asc => [a,b,c]; top-2: [a,b]
        String[] words = {"a","b","c","a","b","c"};
        assertEquals(List.of("a","b"), new Solution().topKFrequentWords(words, 2));
    }

    @Test
    void kEqualsDistinctCount() {
        // k=3 equals number of distinct words => return all three in order
        String[] words = {"cat","dog","cat","bird"};
        assertEquals(List.of("cat","bird","dog"), new Solution().topKFrequentWords(words, 3));
    }

    @Test
    void kExceedsDistinctCount() {
        // k=5 but only 2 distinct words => return both
        String[] words = {"x","y"};
        assertEquals(List.of("x","y"), new Solution().topKFrequentWords(words, 5));
    }

    @Test
    void emptyInput() {
        assertEquals(List.of(), new Solution().topKFrequentWords(new String[]{}, 2));
    }

    @Test
    void singleWord() {
        String[] words = {"hello","hello","hello"};
        assertEquals(List.of("hello"), new Solution().topKFrequentWords(words, 1));
    }

    @Test
    void tiebreakLexAmongTopFreq() {
        // zoo=3, ant=3, mango=1 => tie at 3; lex asc: ant < zoo; top-1: [ant]
        String[] words = {"zoo","zoo","zoo","ant","ant","ant","mango"};
        assertEquals(List.of("ant"), new Solution().topKFrequentWords(words, 1));
    }
}
